// src/components/Section/Section.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import Card from "../Card/Card";
import Carousel from "../Carousel/Carousel";
import styles from "./Section.module.css";

function Section({ title, endpoint, isSongsSection = false, showToggle = true }) {
  const [items, setItems] = useState([]);
  const [isCollapsed, setIsCollapsed] = useState(false); // used only for albums

  useEffect(() => {
    axios
      .get(endpoint)
      .then((res) => setItems(res.data))
      .catch((err) => {
        console.error(`Failed to fetch ${title}`, err);
      });
  }, [endpoint, title]);

  const handleToggle = () => {
    setIsCollapsed((prev) => !prev);
  };

  const renderCard = (item) => (
    <Card
      key={item.id}
      image={item.image}
      title={item.title}
      follows={!isSongsSection ? item.follows : undefined}
      likes={isSongsSection ? item.likes : undefined}
    />
  );

  return (
    <section className={styles.section}>
      <div className={styles.header}>
        <h2 className={styles.title}>{title}</h2>

        {!isSongsSection && showToggle && (
          <button className={styles.collapse} onClick={handleToggle}>
            {isCollapsed ? "Show All" : "Collapse"}
          </button>
        )}
      </div>

      {isSongsSection ? (
        // Songs section: ALWAYS carousel
        <Carousel items={items}>{items.map(renderCard)}</Carousel>
      ) : isCollapsed ? (
        // Albums collapsed: carousel
        <Carousel items={items}>{items.map(renderCard)}</Carousel>
      ) : (
        // Albums expanded: grid
        <div className={styles.grid}>{items.map(renderCard)}</div>
      )}
    </section>
  );
}

export default Section;
